extension PrefirePlaybookPlugin: XcodeBuildToolPlugin {
    func createBuildCommands(context: XcodeProjectPlugin.XcodePluginContext, target: XcodeProjectPlugin.XcodeTarget) throws -> [PackagePlugin.Command] {
        let executable = try context.tool(named: "PrefireBinary").url
        let cachePath = context.pluginWorkDirectoryURL.appending(path: "Cache")
        let outputPath = context.pluginWorkDirectoryURL.appending(path: "Generated")
        let targetPath = context.xcodeProject.directoryURL.appending(path: target.displayName)
        var arguments: [String] = [
            "playbook",
            "--output", outputPath.path,
            "--target-path", targetPath.path,
            "--config", context.xcodeProject.directoryURL.path,
            "--cache-base-path", cachePath.path,
            "--verbose",
        ]
        let sources = target.inputFiles.filter { $0.type == .source }.map { $0.url.path }
        arguments.append(contentsOf: sources)
        return [
            .prebuildCommand(
                displayName: "Running Prefire Playbook",
                executable: executable,
                arguments: arguments,
                outputFilesDirectory: outputPath
            ),
        ]
    }
}

public struct Logger {
    public enum Level: Int {
        case errors
        case warnings
        case info
        case verbose
    }
    nonisolated(unsafe) public static var level: Level = .warnings
    static public func verbose(_ items: Any..., separator: String = " ", terminator: String = "\n") {
        guard Level.verbose.rawValue <= Logger.level.rawValue else { return }
        Swift.print(items, separator: separator, terminator: terminator)
    }
    static public func info(_ items: Any..., separator: String = " ", terminator: String = "\n") {
        guard Level.info.rawValue <= Logger.level.rawValue else { return }
        Swift.print(items, separator: separator, terminator: terminator)
    }
    static public func warning(_ items: Any..., separator: String = " ", terminator: String = "\n") {
        guard Level.warnings.rawValue <= Logger.level.rawValue else { return }
        Swift.print(items, separator: separator, terminator: terminator)
    }
    static public func error(_ items: Any..., separator: String = " ", terminator: String = "\n") {
        guard Level.errors.rawValue <= Logger.level.rawValue else { return }
        Swift.print(items, separator: separator, terminator: terminator)
    }
}

struct PrefireCacheManager {
    private let version: String
    private let cacheBasePath: Path?
    init(version: String, cacheBasePath: Path? = nil) {
        self.version = version
        self.cacheBasePath = cacheBasePath
    }
    func loadOrGenerate(
        sources: [Path],
        template: String,
        parseTypes: () throws -> Types,
        parsePreviews: () async throws -> [String: String]
    ) async throws -> (types: Types, previews: [String: String]) {
        let key = fingerprint(for: sources, extra: template)
        let dir = Path.cachesDir(sourcePath: sources.first ?? .current, basePath: cacheBasePath)
        let typesFile = dir + "\(version)-\(key).types"
        let previewsFile = dir + "\(version)-\(key).previews.json"
        var types: Types?
        var previews: [String: String]?
        if typesFile.exists {
            do {
                let data = try Data(contentsOf: typesFile.url)
                types = try NSKeyedUnarchiver.unarchiveTopLevelObjectWithData(data) as? Types
            } catch {
                Logger.warning("⚠️ Failed to read Types cache: \(error)")
            }
        }
        if previewsFile.exists {
            do {
                let data = try Data(contentsOf: previewsFile.url)
                previews = try JSONDecoder().decode([String: String].self, from: data)
            } catch {
                Logger.warning("⚠️ Failed to read Previews cache: \(error)")
            }
        }
        let cacheStamp = typesFile.lastModification
        let isCacheFresh = cacheStamp != nil && sources.allSatisfy {
            ($0.lastModification ?? .distantPast) <= cacheStamp!
        }
        if let types, let previews, isCacheFresh {
            Logger.info("✅ Loaded types and previews from fresh cache.")
            return (types, previews)
        } else {
            Logger.info("♻️ Cache expired or missing. Regenerating…")
        }
        let freshTypes = try parseTypes()
        let freshPreviews = try await parsePreviews()
        let tData = try NSKeyedArchiver.archivedData(withRootObject: freshTypes, requiringSecureCoding: false)
        let pData = try JSONEncoder().encode(freshPreviews)
        try typesFile.parent().mkpath()
        try tData.write(to: typesFile.url)
        try pData.write(to: previewsFile.url)
        Logger.info("💾 Cache written: types and previews.")
        return (freshTypes, freshPreviews)
    }
    private func fingerprint(for sources: [Path], extra: String) -> String {
        var hasher = SHA256()
        for file in sources.sorted(by: { $0.string < $1.string }) {
            hasher.update(data: Data(file.string.utf8))
            hasher.update(with: file.lastModification ?? .distantPast)
        }
        hasher.update(data: Data(extra.utf8))
        return hasher.finalize().hexString
    }
}

public enum PrefireGenerator {
    nonisolated(unsafe) static var startTime = Date()
    public static func generate(
        version: String,
        sources: [Path],
        output: Path,
        arguments: [String: NSObject],
        inlineTemplate: String,
        defaultEnabled: Bool,
        cacheDir: Path? = nil,
        useGroupedSnapshots: Bool
    ) async throws {
        startTime = Date()
        var swiftFiles: Set<Path> = []
        try sources.forEach { path in
            if path.isDirectory {
                swiftFiles.formUnion(try path.recursiveChildren().filter { $0.extension == "swift" })
            } else if path.extension == "swift" {
                swiftFiles.insert(path)
            }
        }
        guard !swiftFiles.isEmpty else {
            Logger.info("No Swift sources found to process.")
            return
        }
        let fileContents: [(Path, String)] = try swiftFiles.map { ($0, try $0.read(.utf8)) }
        let manager = PrefireCacheManager(version: version, cacheBasePath: cacheDir)
        let (types, previews) = try await manager.loadOrGenerate(
            sources: fileContents.map { $0.0 },
            template: inlineTemplate,
            parseTypes: {
                Logger.info("🧩 Parsing Swift files...")
                let results = try fileContents.map { (path, content) in
                    let parser = try FileParserSyntax(
                        contents: content,
                        forceParse: [],
                        parseDocumentation: false,
                        path: path,
                        module: nil
                    )
                    return try parser.parse()
                }
                let types = results.flatMap { $0.types }
                return Types(types: types)
            },
            parsePreviews: {
                Logger.info("🔍 Extracting #Preview bodies...")
                var result: [String: String] = [:]
                for (path, content) in fileContents {
                    guard content.contains("#Preview") else { continue }
                    if let bodies = PreviewLoader.previewBodies(from: content, defaultEnabled: defaultEnabled) {
                        for (i, body) in bodies.enumerated() {
                            let key = "\(path.lastComponentWithoutExtension)_\(i)"
                            result[key] = body
                        }
                    }
                }
                return result
            }
        )
        let previewModels = previews
            .sorted { $0.key > $1.key }
            .compactMap { entry -> [String: Any?]? in
                guard let model = RawPreviewModel(from: entry.value, filename: entry.key) else { return nil }
                var dict = model.makeStencilDict()
                dict["sourceFileName"] = extractFileNameFromKey(entry.key)
                return dict
            }
        let parserResult = FileParserResult(path: nil, module: nil, types: types.types, functions: [], typealiases: [])
        if useGroupedSnapshots {
            var arguments = arguments
            arguments["previewsMacrosDict"] = previewModels as NSArray
            let customizedTemplate = inlineTemplate.replacingOccurrences(of: "{PREVIEW_FILE_NAME}", with: "Preview")
            try renderAndWrite(parserResult: parserResult, inlineTemplate: customizedTemplate, output: output, arguments: arguments)
        } else {
            try generateUngroupedFiles(
                previewModels: previewModels,
                parserResult: parserResult,
                inlineTemplate: inlineTemplate,
                output: output,
                arguments: arguments
            )
        }
        Logger.info("✅ Generation completed in \(startTime.distance(to: Date()).formatted())")
    }
    private static func generateUngroupedFiles(
        previewModels: [[String: Any?]],
        parserResult: FileParserResult,
        inlineTemplate: String,
        output: Path,
        arguments: [String: NSObject]
    ) throws {
        let groupedByFile = Dictionary(grouping: previewModels) { previewModel -> String in
            return previewModel["sourceFileName"] as? String ?? "Unknown"
        }
        Logger.info("📝 Generating \(groupedByFile.count) separate test files...")
        for (fileName, models) in groupedByFile {
            guard fileName != "Unknown" else { continue }
            let outputPath = replacePreviewFileName(in: output, with: fileName)
            var fileArguments = arguments
            fileArguments["previewsMacrosDict"] = models as NSArray
            let customizedTemplate = inlineTemplate.replacingOccurrences(of: "{PREVIEW_FILE_NAME}", with: fileName)
            Logger.info("🖋 Rendering template for \(fileName)...")
            try renderAndWrite(
                parserResult: parserResult,
                inlineTemplate: customizedTemplate,
                output: outputPath,
                arguments: fileArguments
            )
        }
    }
    private static func extractFileNameFromKey(_ key: String) -> String {
        let components = key.components(separatedBy: "_")
        guard !components.isEmpty else { return key }
        if components.count > 1 && Int(components.last!) != nil {
            return components.dropLast().joined(separator: "_")
        }
        return key
    }
    private static func replacePreviewFileName(in path: Path, with fileName: String) -> Path {
        let pathString = path.string
        let updatedPath = pathString.replacingOccurrences(of: "{PREVIEW_FILE_NAME}", with: fileName)
        return Path(updatedPath)
    }
    private static func renderAndWrite(
        parserResult: FileParserResult,
        inlineTemplate: String,
        output: Path,
        arguments: [String: NSObject]
    ) throws {
        Logger.info("🖋 Rendering template...")
        let tpl = StencilTemplate(templateString: inlineTemplate)
        let context = TemplateContext(
            parserResult: parserResult,
            types: Types(types: parserResult.types),
            functions: parserResult.functions,
            arguments: arguments
        )
        let rendered = try tpl.render(context.stencilContext)
        Logger.info("💾 Writing to file: \(output)")
        try output.parent().mkpath()
        try output.write(rendered)
    }
}

static func previewBodies(from content: String, defaultEnabled: Bool) -> [String]? {
    let lines = content.split(separator: "\n", omittingEmptySubsequences: false)
    var previewBodies: [String] = []
    var currentBody: String = ""
    var previewWasFound = false
    var viewMustBeLoaded = defaultEnabled
    var braceBalance: Int? = nil
    for line in lines {
        if line.hasPrefix(Constants.previewMarker) {
            previewWasFound = true
            currentBody = ""
            braceBalance = nil
        }
        guard previewWasFound else { continue }
        let braceChange = line.reduce(0) { (count, char) in
            if char == Constants.openingBrace {
                return count + 1
            } else if char == Constants.closingBrace {
                return count - 1
            }
            return count
        }
        if braceChange != 0 || braceBalance != nil {
            braceBalance = (braceBalance ?? 0) + braceChange
        }
        if defaultEnabled {
            if line.contains(Constants.prefireDisableMarker) {
                viewMustBeLoaded = false
            }
        } else if !viewMustBeLoaded {
            viewMustBeLoaded = line.contains(Constants.prefireEnabledMarker)
        }
        currentBody.append(String(line) + "\n")
        if braceBalance == 0 {
            if !currentBody.isEmpty, viewMustBeLoaded {
                previewBodies.append(currentBody)
            }
            previewWasFound = false
            viewMustBeLoaded = defaultEnabled
        }
    }
    return previewBodies.isEmpty ? nil : previewBodies
}

final class PreviewParser: SyntaxVisitor {
    private(set) var body: String?
    private(set) var properties: [String] = []
    enum Constants {
        static let previewable = "Previewable"
    }
    init() {
        super.init(viewMode: .sourceAccurate)
    }
    override func visit(_ node: VariableDeclSyntax) -> SyntaxVisitorContinueKind {
        guard node.attributes.contain(matchingName: Constants.previewable) else {
            appendItemToBody(node)
            return .skipChildren
        }
        var resultVariable = node
        resultVariable.attributes = node.attributes.remove(matchingName: Constants.previewable)
        properties.append("\(resultVariable.trimmed)")
        return .skipChildren
    }
    override func visit(_ node: CodeBlockItemSyntax) -> SyntaxVisitorContinueKind {
        if node.item.is(VariableDeclSyntax.self) || node.item.is(MacroExpansionExprSyntax.self) {
            return .visitChildren
        }
        appendItemToBody(node)
        return .skipChildren
    }
}

extension RawPreviewModel {
    private enum Markers {
        static let previewMacro = "#Preview"
        static let traits = "traits: "
    }
    private enum Constants {
        static let defaultTrait = ".device"
    }
    /// Initialization from the macro Preview body
    /// - Parameters:
    ///   - macroBody: Preview View body
    ///   - filename: File name in which the macro was found
    init?(from macroBody: String, filename: String) {
        guard !macroBody.isEmpty else { return nil }
        var lines = macroBody.split(separator: "\n", omittingEmptySubsequences: false).dropLast(2)
        let firstLine = lines.removeFirst()
        let parts = firstLine.split(separator: "\"")
        if let namePart = parts.first(where: { !$0.contains(Markers.previewMacro) }) {
            self.displayName = String(namePart)
        } else {
            self.displayName = filename
        }
        var previewTrait: String?
        if let range = firstLine.range(of: Markers.traits) {
            let substring = firstLine[range.upperBound...]
            let endIndex = Self.findTraitsEndIndex(in: substring)
            if let endIndex = endIndex {
                previewTrait = String(substring[..<endIndex])
            }
        }
        self.traits = Self.parseTraits(from: previewTrait)
        let macroBodySyntax = Parser.parse(source: macroBody)
        let previewParser = PreviewParser()
        previewParser.walk(macroBodySyntax)
        self.properties = previewParser.properties.first
        if let firstProperty = self.properties,
           previewParser.properties.count >= 2 {
            self.properties = previewParser.properties.dropFirst().reduce(firstProperty) {
                var properties = $0
                properties = properties + "\n" + $1
                return properties
            }
        }
        body = previewParser.body ?? ""
    }
    /// Parse traits from the raw trait string
    /// Handles single traits, comma-separated traits, and function-style traits
    private static func parseTraits(from rawTraits: String?) -> [String] {
        guard let rawTraits = rawTraits?.trimmingCharacters(in: .whitespacesAndNewlines), 
              !rawTraits.isEmpty else {
            return [Constants.defaultTrait]
        }
        var traits: [String] = []
        traits.reserveCapacity(4) // Most common case: 1-3 traits
        let startIndex = rawTraits.startIndex
        let endIndex = rawTraits.endIndex
        var currentStart = startIndex
        var currentIndex = startIndex
        var parenthesesDepth = 0
        var insideQuotes = false
        var quoteChar: Character?
        while currentIndex < endIndex {
            let char = rawTraits[currentIndex]
            switch char {
            case "\"", "'":
                if !insideQuotes {
                    insideQuotes = true
                    quoteChar = char
                } else if char == quoteChar {
                    insideQuotes = false
                    quoteChar = nil
                }
            case "(":
                if !insideQuotes {
                    parenthesesDepth += 1
                }
            case ")":
                if !insideQuotes {
                    parenthesesDepth -= 1
                }
            case ",":
                if !insideQuotes && parenthesesDepth == 0 {
                    let traitSubstring = rawTraits[currentStart..<currentIndex]
                    let trimmedTrait = traitSubstring.trimmingCharacters(in: .whitespacesAndNewlines)
                    if !trimmedTrait.isEmpty {
                        traits.append(String(trimmedTrait))
                    }
                    currentStart = rawTraits.index(after: currentIndex)
                }
            default:
                break
            }
            currentIndex = rawTraits.index(after: currentIndex)
        }
        let lastTraitSubstring = rawTraits[currentStart..<endIndex]
        let trimmedLastTrait = lastTraitSubstring.trimmingCharacters(in: .whitespacesAndNewlines)
        if !trimmedLastTrait.isEmpty {
            traits.append(String(trimmedLastTrait))
        }
        return traits.isEmpty ? [Constants.defaultTrait] : traits
    }
    /// Find the correct end index for traits, respecting parentheses balance
    private static func findTraitsEndIndex(in substring: Substring) -> String.Index? {
        var parenthesesDepth = 0
        var insideQuotes = false
        var quoteChar: Character?
        var currentIndex = substring.startIndex
        let endIndex = substring.endIndex
        while currentIndex < endIndex {
            let char = substring[currentIndex]
            switch char {
            case "\"", "'":
                if !insideQuotes {
                    insideQuotes = true
                    quoteChar = char
                } else if char == quoteChar {
                    insideQuotes = false
                    quoteChar = nil
                }
            case "(":
                if !insideQuotes {
                    parenthesesDepth += 1
                }
            case ")":
                if !insideQuotes {
                    if parenthesesDepth == 0 {
                        return currentIndex
                    }
                    parenthesesDepth -= 1
                }
            default:
                break
            }
            currentIndex = substring.index(after: currentIndex)
        }
        return nil
    }
}

extension EmbeddedTemplates {
    public static let previewModels = #"""
import SwiftUI
import Prefire
{% for import in argument.imports %}
import {{ import }}
{% endfor %}
{% for import in argument.testableImports %}
@testable import {{ import }}
{% endfor %}
public enum PreviewModels {
    @MainActor
    public static var models: [PreviewModel] = {
        var views: [PreviewModel] = []
        #if !PLAYBOOK_DISABLED
        {% for type in types.types where type.implements.PrefireProvider or type.based.PrefireProvider or type|annotated:"PrefireProvider" %}
        views.append(contentsOf: createModel(for: {{ type.name }}.self, name: "{{ type.name | replace:"_Previews","" | replace:"_Preview","" }}"))
        {% endfor %}
        {% if argument.previewsMacrosDict %}
        views.append(contentsOf: MacroPreviews.previews)
        {% endif %}
        #endif
        return views.sorted(by: { $0.name > $1.name || $0.story ?? "" > $1.story ?? "" })
    }()
    @inlinable
    @MainActor
    static func createModel<Preview: PreviewProvider>(for preview: Preview.Type, name: String) -> [PreviewModel] {
        var views: [PreviewModel] = []
        for (index, view) in Preview._allPreviews.enumerated() {
            views.append(
                PreviewModel(
                    id: name + "\(index)" + String(describing: self),
                    content: { return view.content },
                    name: name,
                    type: view.layout == .device ? .screen : .component,
                    device: view.device
                )
            )
        }
        return views
    }
}
{% if argument.previewsMacrosDict %}
@MainActor
private struct MacroPreviews {
    {% for macroModel in argument.previewsMacrosDict %}
    {% if macroModel.properties %}
    struct PreviewWrapper{{ macroModel.componentTestName }}: SwiftUI.View {
    {{ macroModel.properties }}
        var body: some View {
        {{ macroModel.body|indent:8 }}
        }
    }
    {% endif %}
    {% endfor %}
    static var previews: [PreviewModel] = [
        {% for macroModel in argument.previewsMacrosDict %}
        {% if macroModel.properties %}
        PreviewModel(content: { PreviewWrapper{{ macroModel.componentTestName }}() }, name: "{{ macroModel.displayName }}"),
        {% else %}
        PreviewModel(content: {
            {{ macroModel.body|indent:12 }}
        }, name: "{{ macroModel.displayName }}"),
        {% endif %}
        {% endfor %}
    ]
}
{% endif %}
"""#
}

struct GeneratedPlaybookOptions {
    var targetPath: String?
    var sources: [Path]
    var output: Path
    var previewDefaultEnabled: Bool
    var template: Path?
    var cacheBasePath: Path?
    var imports: [String]?
    var testableImports: [String]?
    init(targetPath: String?, sources: [String], output: String?, template: String?, cacheBasePath: String?, config: Config?) throws {
        self.targetPath = config?.playbook.targetPath ?? targetPath
        self.sources = sources.isEmpty ? [.current] : sources.compactMap({ Path($0) })
        self.output = (output.flatMap({ Path($0) }) ?? .current) + Constants.defaultOutputName
        previewDefaultEnabled = config?.playbook.previewDefaultEnabled ?? true
        if let template = config?.playbook.template, let targetPath {
            let targetURL = URL(filePath: targetPath)
            let templateURL = targetURL.appending(path: template)
            self.template = Path(templateURL.absoluteURL.path(percentEncoded: false))
        } else if let template {
            self.template = Path(template)
        }
        self.cacheBasePath = cacheBasePath.flatMap({ Path($0) })
        imports = config?.playbook.imports
        testableImports = config?.playbook.testableImports
    }
}

enum GeneratePlaybookCommand {
    private enum Keys {
        static let imports = "imports"
        static let testableImports = "testableImports"
    }
    static func run(_ options: GeneratedPlaybookOptions) async throws {
        try await PrefireGenerator.generate(
            version: Prefire.Version.value,
            sources: options.sources,
            output: options.output,
            arguments: await makeArguments(for: options),
            inlineTemplate: try options.template?.read(.utf8) ?? EmbeddedTemplates.previewModels,
            defaultEnabled: options.previewDefaultEnabled,
            cacheDir: options.cacheBasePath,
            useGroupedSnapshots: true // Playbooks are always grouped
        )
    }
    static func makeArguments(for options: GeneratedPlaybookOptions) async -> [String: NSObject] {
        Logger.info(
            """
            Prefire configuration
                ➜ Template path: \(options.template ?? "default")
                ➜ Generated models path: \(options.output)
                ➜ Preview default enabled: \(options.previewDefaultEnabled)
            """
        )
        return [
            Keys.imports: options.imports as? NSArray,
            Keys.testableImports: options.testableImports as? NSArray
        ].filter({ $0.value != nil }) as? [String: NSObject] ?? [:]
    }
}
